+    // =========================================================================
+    // Shadow Router - Predictive Pipelining
+    // =========================================================================
+
+    /// Load all 32 router weights into RAM (dequantized to F32)
+    /// Router weights are tiny: 4096 × 8 × 4 bytes = 128KB per layer = 4MB total
+    /// This enables running routers on CPU 1-2 layers ahead of GPU
+    pub fn loadAllRouters(
+        self: *Self,
+        gguf_loader: anytype, // *gguf_loader.GGUFLoader
+        n_layers: u32,
+    ) !void {
+        const n_embd: u32 = 4096;
+        const n_expert: u32 = 8;
+        const router_size = n_embd * n_expert;
+
+        log.info("🔮 Loading Shadow Routers for {d} layers (~{d}KB total)...", .{
+            n_layers,
+            (router_size * @sizeOf(f32) * n_layers) / 1024,
+        });
+
+        for (0..@min(n_layers, 32)) |layer| {
+            // Build tensor name: "blk.{layer}.ffn_gate_inp.weight"
+            var name_buf: [64]u8 = undefined;
+            const name = std.fmt.bufPrint(&name_buf, "blk.{d}.ffn_gate_inp.weight", .{layer}) catch continue;
+
+            // Try to find and load this tensor
+            const tensor_data = gguf_loader.getTensorData(name) catch |err| {
+                log.warn("   Layer {d}: Router not found ({s})", .{ layer, @errorName(err) });
+                continue;
+            };
+
+            // Dequantize Q8_0 to F32 for fast CPU computation
+            const router_f32 = try self.dequantizeQ8ToF32(tensor_data, router_size);
+            self.shadow_router_weights[layer] = router_f32;
+        }
+
+        // Count how many we loaded
+        var loaded: u32 = 0;
+        for (self.shadow_router_weights) |w| {
+            if (w != null) loaded += 1;
+        }
+
+        if (loaded > 0) {
+            self.shadow_router_enabled = true;
+            log.info("✅ Shadow Router enabled: {d}/{d} layers loaded", .{ loaded, n_layers });
+            log.info("   Lookahead: {d} layers ahead", .{self.shadow_router_lookahead});
+        } else {
+            log.warn("⚠️  Shadow Router disabled: no routers loaded", .{});
+        }
+    }
+
+    /// Dequantize Q8_0 data to F32 for CPU router computation
+    fn dequantizeQ8ToF32(self: *Self, q8_data: []const u8, expected_elements: u32) ![]f32 {
+        const Q8_BLOCK_SIZE = 32;
+        const Q8_BLOCK_BYTES = 34; // 2 (f16 scale) + 32 (i8 values)
+
+        const n_blocks = q8_data.len / Q8_BLOCK_BYTES;
+        const n_elements = n_blocks * Q8_BLOCK_SIZE;
+
+        if (n_elements < expected_elements) {
+            return error.InsufficientData;
+        }
+
+        const result = try self.allocator.alloc(f32, expected_elements);
+        errdefer self.allocator.free(result);
+
+        var block_idx: usize = 0;
+        while (block_idx < n_blocks and block_idx * Q8_BLOCK_SIZE < expected_elements) : (block_idx += 1) {
+            const block_offset = block_idx * Q8_BLOCK_BYTES;
+            const out_offset = block_idx * Q8_BLOCK_SIZE;
+
+            // Read scale (f16 → f32)
+            const scale_bits = std.mem.readInt(u16, q8_data[block_offset..][0..2], .little);
+            const scale = @as(f32, @bitCast(@as(u32, scale_bits) << 16)); // Simplified f16→f32
+
+            // Dequantize values
+            for (0..Q8_BLOCK_SIZE) |i| {
+                if (out_offset + i >= expected_elements) break;
+                const quant_val = @as(i8, @bitCast(q8_data[block_offset + 2 + i]));
+                result[out_offset + i] = scale * @as(f32, @floatFromInt(quant_val));
+            }
+        }
+
+        return result;
+    }
+
+    /// Free all shadow router weights
+    pub fn freeShadowRouters(self: *Self) void {
+        for (0..32) |i| {
+            if (self.shadow_router_weights[i]) |w| {
+                self.allocator.free(w);
+                self.shadow_router_weights[i] = null;
+            }
+        }
+        self.shadow_router_enabled = false;
+    }
+
+    /// Run shadow router on CPU to predict experts for a future layer
+    /// Call this WHILE the GPU is computing the current layer
+    /// Returns top-2 expert indices for the target layer
+    pub fn shadowRouterPredict(
+        self: *Self,
+        hidden_state: []const f32, // Current hidden state [n_embd]
+        target_layer: u32,
+    ) ?[2]u8 {
+        if (!self.shadow_router_enabled) return null;
+        if (target_layer >= 32) return null;
+
+        const router_weights = self.shadow_router_weights[target_layer] orelse return null;
+
+        const n_embd: u32 = 4096;
+        const n_expert: u32 = 8;
+
+        // Compute router logits: logits = hidden_state @ router_weights.T
+        // router_weights is [n_expert, n_embd] stored row-major
+        var logits: [8]f32 = undefined;
+
+        for (0..n_expert) |expert_idx| {
+            var sum: f32 = 0.0;
+            const weight_offset = expert_idx * n_embd;
+
+            // Dot product (could use SIMD here for more speed)
+            for (0..n_embd) |i| {
+                sum += hidden_state[i] * router_weights[weight_offset + i];
+            }
+            logits[expert_idx] = sum;
+        }
+
+        // Find top-2 experts
+        var top1_idx: u8 = 0;
+        var top2_idx: u8 = 1;
+        var top1_val = logits[0];
+        var top2_val = logits[1];
+
+        if (top2_val > top1_val) {
+            const tmp_idx = top1_idx;
+            const tmp_val = top1_val;
+            top1_idx = top2_idx;
+            top1_val = top2_val;
+            top2_idx = tmp_idx;
+            top2_val = tmp_val;
+        }
+
+        for (2..8) |i| {
+            const idx: u8 = @intCast(i);
+            if (logits[i] > top1_val) {
+                top2_idx = top1_idx;
+                top2_val = top1_val;
+                top1_idx = idx;
+                top1_val = logits[i];
+            } else if (logits[i] > top2_val) {
+                top2_idx = idx;
+                top2_val = logits[i];
+            }
+        }
+
+        return .{ top1_idx, top2_idx };
+    }
+
+    /// Queue experts for prefetch based on shadow router prediction
+    pub fn queueShadowPrefetch(self: *Self, layer: u8, experts: [2]u8) void {
+        if (self.shadow_prefetch_count >= 4) return;
+
+        // Add to queue with priority (closer layers = higher priority)
+        for (experts) |expert_id| {
+            if (self.shadow_prefetch_count >= 4) break;
+
+            // Check if already in queue
+            var already_queued = false;
+            for (0..self.shadow_prefetch_count) |i| {
+                if (self.shadow_prefetch_queue[i].layer == layer and
+                    self.shadow_prefetch_queue[i].expert_id == expert_id)
+                {
+                    already_queued = true;
+                    break;
+                }
+            }
+
+            if (!already_queued) {
+                self.shadow_prefetch_queue[self.shadow_prefetch_count] = .{
+                    .layer = layer,
+                    .expert_id = expert_id,
+                    .priority = 32 - layer, // Higher priority for closer layers
+                };
+                self.shadow_prefetch_count += 1;
+            }
+        }
+    }
+
+    /// Get next expert to prefetch from queue
+    pub fn popShadowPrefetch(self: *Self) ?struct { layer: u8, expert_id: u8 } {
+        if (self.shadow_prefetch_count == 0) return null;
+
+        // Find highest priority
+        var best_idx: u8 = 0;
+        var best_priority: u8 = 0;
+        for (0..self.shadow_prefetch_count) |i| {
+            if (self.shadow_prefetch_queue[i].priority > best_priority) {
+                best_priority = self.shadow_prefetch_queue[i].priority;
+                best_idx = @intCast(i);
+            }
+        }
+
+        const result = self.shadow_prefetch_queue[best_idx];
+
+        // Remove from queue (shift remaining)
+        for (best_idx..self.shadow_prefetch_count - 1) |i| {
+            self.shadow_prefetch_queue[i] = self.shadow_prefetch_queue[i + 1];
+        }
+        self.shadow_prefetch_count -= 1;
+
+        return .{ .layer = result.layer, .expert_id = result.expert_id };
+    }
+
+    /// Clear prefetch queue
+    pub fn clearShadowPrefetchQueue(self: *Self) void {
+        self.shadow_prefetch_count = 0;
+    }
+
+    /// Get shadow router statistics
+    pub fn getShadowRouterStats(self: *Self) struct {
+        hits: u64,
+        misses: u64,
+        accuracy: f32,
+        enabled: bool,
+        layers_loaded: u32,
+    } {
+        var loaded: u32 = 0;
+        for (self.shadow_router_weights) |w| {
+            if (w != null) loaded += 1;
+        }
+
+        const total = self.shadow_router_hits + self.shadow_router_misses;
+        const accuracy = if (total > 0)
+            @as(f32, @floatFromInt(self.shadow_router_hits)) / @as(f32, @floatFromInt(total))
+        else
+            0.0;
+
+        return .{
+            .hits = self.shadow_router_hits,
+            .misses = self.shadow_router_misses,
+            .accuracy = accuracy,
+            .enabled = self.shadow_router_enabled,
+            .layers_loaded = loaded,
+        };
+    }
+
+    /// Log shadow router statistics
+    pub fn logShadowRouterStats(self: *Self) void {
+        const stats = self.getShadowRouterStats();
+        if (stats.enabled) {
+            log.info("🔮 Shadow Router: {d} layers loaded, lookahead={d}", .{
+                stats.layers_loaded,
+                self.shadow_router_lookahead,
+            });
+            if (stats.hits + stats.misses > 0) {
+                log.info("   Predictions: {d} hits, {d} misses, {d:.1}% accuracy", .{
+                    stats.hits,
+                    stats.misses,
+                    stats.accuracy * 100.0,
+                });
+            }
+        }
+    }
+
